const fs = require('fs');
const path = require('path');

const repoRoot = path.resolve(__dirname, '..');
const gitHooksDir = path.join(repoRoot, '.git', 'hooks');

if (!fs.existsSync(gitHooksDir)) {
  console.error('Unable to find .git/hooks. Run this script from a cloned git repository.');
  process.exit(1);
}

const hookPath = path.join(gitHooksDir, 'post-commit');
const hookContent = `#!/bin/sh
# Auto-generated by scripts/install-changelog-hook.js
# Adds a changelog entry after each commit, then amends commit once.

if [ "$CHANGELOG_AMEND" = "1" ]; then
  exit 0
fi

node scripts/update-changelog-from-last-commit.js

if ! git diff --cached --quiet -- apps/web/src/data/admin-changelog.json; then
  CHANGELOG_AMEND=1 git commit --amend --no-edit --no-verify >/dev/null 2>&1
fi
`;

fs.writeFileSync(hookPath, hookContent, 'utf8');
try {
  fs.chmodSync(hookPath, 0o755);
} catch {
  // Windows may ignore chmod; hook still works through git bash environments.
}

console.log('Installed git post-commit hook at .git/hooks/post-commit');
